# E2-Skeptic three-route assess for S41-T1-B-E2
def assess(record: dict) -> str:
    required = {'version', 'effects', 'stored_hash', 'cursor', 'key', 'case_id', 'request_hash'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    try:
        ok = not (record["effects"] > 1 or record["request_hash"] != record["stored_hash"])
    except Exception:
        return 'RETURN_IDEMPOTENCY_CONFLICT'
    return 'PASS' if ok else 'RETURN_IDEMPOTENCY_CONFLICT'

record = {"case_id": "CASO-ARE-041-1B", **{"key":"idem-are-1","request_hash":"abc","stored_hash":"abc","effects":1,"cursor":"job-020","version":"v1"}}
valid = dict(record)
invalid = dict(valid)
# adverse: invert first boolean flag if any
_flipped=False
for _k,_v in list(invalid.items()):
    if isinstance(_v,bool):
        invalid[_k]= (not _v)
        _flipped=True
        break
if not _flipped and isinstance(invalid.get('stages'), list):
    invalid['stages']=list(reversed(invalid['stages']))
elif not _flipped and 'dependencies' in invalid:
    invalid['dependencies']=[["domain","infrastructure"]]
incomplete={k:v for k,v in valid.items() if k != 'version'}
print(assess(valid), assess(invalid), assess(incomplete))

